using System.Collections.Concurrent;

namespace sv_01fbacc782d14c99a326e466b44775a3.Services;

/// <summary>
/// Singleton store that holds wizard state keyed by session ID.
/// Works across render mode boundaries because both static SSR and
/// interactive server components resolve the same singleton instance.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
    {
        var state = _states.GetOrAdd(sessionId, _ => new WizardState());
        state.LastAccessed = DateTime.UtcNow;
        return state;
    }
}

namespace sv_01fbacc782d14c99a326e466b44775a3.Services;

/// <summary>
/// Scoped service that resolves the wizard session ID from the HTTP cookie
/// and provides access to the singleton WizardStateStore.
///
/// In static SSR (layout): HttpContext is always available.
/// In interactive server (pages): HttpContext is available during prerender;
/// the session ID is captured on first access so it remains usable after
/// the circuit is established and HttpContext becomes null.
/// </summary>
public class WizardSession
{
    private readonly WizardStateStore _store;
    private readonly IHttpContextAccessor _httpContextAccessor;
    private string? _cachedSessionId;

    public WizardSession(WizardStateStore store, IHttpContextAccessor httpContextAccessor)
    {
        _store = store;
        _httpContextAccessor = httpContextAccessor;
    }

    public const string CookieName = "WizardSessionId";

    public string? SessionId
    {
        get
        {
            // Once captured, reuse for the lifetime of this scoped instance.
            if (_cachedSessionId is not null)
                return _cachedSessionId;

            var context = _httpContextAccessor.HttpContext;
            if (context is null)
                return null;

            if (!context.Request.Cookies.TryGetValue(CookieName, out var id) || string.IsNullOrEmpty(id))
            {
                id = Guid.NewGuid().ToString("N");
                context.Response.Cookies.Append(CookieName, id, new CookieOptions
                {
                    HttpOnly = true,
                    SameSite = SameSiteMode.Strict,
                    MaxAge = TimeSpan.FromHours(4)
                });
            }

            _cachedSessionId = id;
            return id;
        }
    }

    public WizardState? State => SessionId is not null ? _store.GetOrCreate(SessionId) : null;
}

