@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_01fbacc782d14c99a326e466b44775a3.Services
@inject WizardSession Wizard
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

@if (_state is not null)
{
    <EditForm Model="_state.Personal" OnValidSubmit="Next" FormName="personal-info">
        <div class="mb-3">
            <label class="form-label">Full Name</label>
            <InputText class="form-control" @bind-Value="_state.Personal.Name" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email Address</label>
            <InputText class="form-control" @bind-Value="_state.Personal.Email" />
        </div>
        <button type="submit" class="btn btn-primary">Next →</button>
    </EditForm>
}

@code {
    private WizardState? _state;

    protected override void OnInitialized()
    {
        _state = Wizard.State;
    }

    private void Next()
    {
        _state!.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_01fbacc782d14c99a326e466b44775a3.Services
@inject WizardSession Wizard
