<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardRoute)
            {
                @* Progress bar rendered statically — re-renders on every navigation *@
                <nav class="wizard-progress d-flex align-items-center gap-2 me-auto">
                    @foreach (var step in _steps)
                    {
                        var isCurrent = step.Number == CurrentStep;
                        var isCompleted = WizardState?.CompletedSteps.Contains(step.Number) == true;
                        <a href="@step.Href"
                           class="badge @(isCurrent ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary") text-decoration-none">
                            @step.Number. @step.Label
                        </a>
                    }
                    <span class="ms-2 text-muted small">Step @CurrentStep of @_steps.Length</span>
                </nav>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

