@code {
    private static readonly (int Number, string Label, string Href)[] _steps =
    [
        (1, "Personal Info", "/apply/personal-info"),
        (2, "Experience",    "/apply/experience"),
        (3, "References",    "/apply/references"),
        (4, "Review",        "/apply/review"),
    ];

    private WizardState? WizardState => Wizard.State;

    private bool IsWizardRoute =>
        Nav.Uri.Contains("/apply/", StringComparison.OrdinalIgnoreCase);

    private int CurrentStep =>
        _steps.FirstOrDefault(s => Nav.Uri.Contains(s.Href, StringComparison.OrdinalIgnoreCase)).Number;
}", "path": "/tmp/sv-01fbacc782d14c99a326e466b44775a3/Components/Layout/MainLayout.razor"}
